482	    static SetConcurrentLimit(audioKey: string, maxCount: number): void {
483	        if (maxCount <= 0 && maxCount !== -1) {
484	            console.warn(`無效的並發限制數量: ${maxCount}，應該大於 0 或設為 -1`);
485	            return;
486	        }
487	
488	        if (maxCount === -1) {
489	            this.m_concurrentLimits.delete(audioKey);
490	        } else {
491	            this.m_concurrentLimits.set(audioKey, maxCount);
492	        }
493	    }
494	
495	    /**
496	     * 設定預設並發限制
497	     * @description 設定所有音效的預設並發限制，對於沒有特別設定的音效生效
498	     * @param maxCount 預設最大並發數量，設為 -1 表示無限制
499	     * @example
500	     * ```typescript
501	     * // 設定所有音效預設最多同時播放 5 個
502	     * AudioManager.SetDefaultConcurrentLimit(5);
503	     *
504	     * // 移除預設限制
505	     * AudioManager.SetDefaultConcurrentLimit(-1);
506	     * ```
507	     */
508	    static SetDefaultConcurrentLimit(maxCount: number): void {
509	        if (maxCount <= 0 && maxCount !== -1) {
