511	            return;
512	        }
513	        this.m_defaultConcurrentLimit = maxCount;
514	    }
515	
516	    /**
517	     * 設定超限處理策略
518	     * @description 設定當並發播放數量超過限制時的處理方式
519	     * @param strategy 處理策略：'ignore' 忽略新請求；'replace-oldest' 停止最舊的音效
520	     * @example
521	     * ```typescript
522	     * // 設定為忽略新請求
523	     * AudioManager.SetOverflowStrategy(ConcurrentOverflowStrategy.IGNORE);
524	     *
525	     * // 設定為停止最舊的音效
526	     * AudioManager.SetOverflowStrategy(ConcurrentOverflowStrategy.REPLACE_OLDEST);
527	     * ```
528	     */
529	    static SetOverflowStrategy(strategy: ConcurrentOverflowStrategy): void {
530	        this.m_overflowStrategy = strategy;
531	    }
532	
533	    /**
534	     * 查詢當前音效播放數量
535	     * @description 取得指定音效當前正在播放的實例數量
536	     * @param audioKey 音效鍵名
537	     * @returns 當前播放數量
538	     * @example
539	     * ```typescript
540	     * const currentCount = AudioManager.GetCurrentPlayingCount("skill_explosion");
541	     * console.log(`技能爆炸音效當前播放數量: ${currentCount}`);
542	     * ```
543	     */
544	    static GetCurrentPlayingCount(audioKey: string): number {
545	        const instances = this.m_playingInstances.get(audioKey);
546	        return instances ? instances.size : 0;
547	    }
548	
549	    /**
550	     * 查詢音效並發限制
551	     * @description 取得指定音效的並發限制設定
552	     * @param audioKey 音效鍵名
553	     * @returns 並發限制數量，-1 表示無限制
554	     * @example
555	     * ```typescript
556	     * const limit = AudioManager.GetConcurrentLimit("skill_explosion");
557	     * if (limit === -1) {
558	     *     console.log("技能爆炸音效無並發限制");
559	     * } else {
560	     *     console.log(`技能爆炸音效並發限制: ${limit}`);
561	     * }
562	     * ```
563	     */
564	    static GetConcurrentLimit(audioKey: string): number {
565	        return this.m_concurrentLimits.get(audioKey) || this.m_defaultConcurrentLimit;
566	    }
567	
568	    /**
569	     * 停止指定音效的所有實例
570	     * @description 停止指定音效的所有正在播放的實例
571	     * @param audioKey 音效鍵名
572	     * @returns 停止的音效數量
573	     * @example
574	     * ```typescript
575	     * const stoppedCount = AudioManager.StopAllInstances("skill_explosion");
576	     * console.log(`已停止 ${stoppedCount} 個技能爆炸音效`);
577	     * ```
578	     */
579	    static StopAllInstances(audioKey: string): number {
580	        const instances = this.m_playingInstances.get(audioKey);
581	        if (!instances || instances.size === 0) {
582	            return 0;
583	        }
584	
585	        let stoppedCount = 0;
586	        for (const audioId of instances) {
587	            soundAudioManager.Stop(audioId);
588	            this.m_instanceMetadata.delete(audioId);
589	            stoppedCount++;
590	        }
591	
592	        instances.clear();
593	        return stoppedCount;
594	    }
595	
596	    /**
597	     * 清除所有並發限制設定
598	     * @description 清除所有音效的並發限制設定和播放記錄
599	     * @example
600	     * ```typescript
601	     * AudioManager.ClearAllConcurrentLimits();
602	     * ```
603	     */
604	    static ClearAllConcurrentLimits(): void {
605	        this.m_concurrentLimits.clear();
606	        this.m_playingInstances.clear();
607	        this.m_instanceMetadata.clear();
608	        this.m_defaultConcurrentLimit = -1;
609	        this.m_overflowStrategy = ConcurrentOverflowStrategy.IGNORE;
610	    }
611	
612	    // =================================================================
613	    // 內部方法 (Private Methods)
614	    // =================================================================
615	
616	    /**
617	     * 檢查並發限制
618	     * @description 檢查指定音效是否可以播放，如果超過限制則根據策略處理
619	     * @param audioKey 音效鍵名
620	     * @returns 是否可以播放
621	     */
622	    private static CheckConcurrentLimit(audioKey: string): boolean {
623	        const limit = this.GetConcurrentLimit(audioKey);
624	        if (limit === -1) {
625	            return true; // 無限制
626	        }
627	
628	        const currentCount = this.GetCurrentPlayingCount(audioKey);
629	        if (currentCount < limit) {
630	            return true; // 未超過限制
631	        }
632	
633	        // 超過限制，根據策略處理
634	        if (this.m_overflowStrategy === ConcurrentOverflowStrategy.REPLACE_OLDEST) {
635	            this.StopOldestInstance(audioKey);
636	            return true;
637	        }
638	
639	        return false; // 忽略新請求
640	    }
641	
642	    /**
643	     * 停止最舊的音效實例
644	     * @description 停止指定音效的最舊播放實例
645	     * @param audioKey 音效鍵名
646	     */
647	    private static StopOldestInstance(audioKey: string): void {
648	        const instances = this.m_playingInstances.get(audioKey);
649	        if (!instances || instances.size === 0) {
650	            return;
651	        }
652	
653	        let oldestId = -1;
654	        let oldestTime = Number.MAX_VALUE;
655	
656	        // 找出最舊的實例
657	        for (const audioId of instances) {
658	            const metadata = this.m_instanceMetadata.get(audioId);
659	            if (metadata && metadata.startTime < oldestTime) {
660	                oldestTime = metadata.startTime;
661	                oldestId = audioId;
662	            }
663	        }
664	
665	        if (oldestId !== -1) {
666	            soundAudioManager.Stop(oldestId);
667	            this.RemovePlayingInstance(audioKey, oldestId);
668	        }
669	    }
670	
671	    /**
672	     * 添加播放實例
673	     * @description 將新的音效實例添加到追蹤列表
674	     * @param audioKey 音效鍵名
675	     * @param audioId 音效 ID
676	     */
677	    private static AddPlayingInstance(audioKey: string, audioId: number): void {
678	        if (!this.m_playingInstances.has(audioKey)) {
679	            this.m_playingInstances.set(audioKey, new Set());
680	        }
681	        this.m_playingInstances.get(audioKey)!.add(audioId);
682	
683	        // 記錄元數據
684	        this.m_instanceMetadata.set(audioId, {
685	            audioKey: audioKey,
686	            startTime: Date.now()
687	        });
688	    }
689	
690	    /**
691	     * 移除播放實例
692	     * @description 從追蹤列表中移除指定的音效實例
693	     * @param audioKey 音效鍵名
694	     * @param audioId 音效 ID
695	     */
696	    private static RemovePlayingInstance(audioKey: string, audioId: number): void {
697	        const instances = this.m_playingInstances.get(audioKey);
698	        if (instances) {
699	            instances.delete(audioId);
700	            if (instances.size === 0) {
701	                this.m_playingInstances.delete(audioKey);
702	            }
703	        }
704	
705	        this.m_instanceMetadata.delete(audioId);
706	    }
707	}
