209	    private BuildMultiplierList( features: ar2es2Proto.IFeatureResult[] ): MultiplierInfo[]
210	    {
211	        // 同一位置可能在 Positions 中出現多次（server 送多段倍率），以 compound 方式合算避免並行 race。
212	        const compoundMap = new Map<string, MultiplierInfo>();
213	        for ( const wf of features )
214	        {
215	            const positions = wf.Positions ?? [];
216	            for ( let i = 0; i < positions.length; i++ )
217	            {
218	                const decoded = Common.DecodeServerPosByRowConfig( positions[ i ] );
219	                if ( !decoded ) continue;
220	                // 每個位置有獨立倍率；退回 index 0 作為保底
221	                const multiplier = wf.Multipliers?.[ i ] ?? wf.Multipliers?.[ 0 ] ?? 1;
222	                const key = `${ decoded.col },${ decoded.row }`;
223	                const existing = compoundMap.get( key );
224	                if ( existing )
225	                {
226	                    existing.multiplier *= multiplier;
227	                }
228	                else
229	                {
230	                    compoundMap.set( key, { col: decoded.col, row: decoded.row, multiplier } );
231	                }
232	            }
233	        }
234	        return Array.from( compoundMap.values() );
