238	    private async PlayMultiplierWithStamp( list: MultiplierInfo[] ): Promise<void>
239	    {
240	        console.log( `[Multiplier] PlayMultiplierWithStamp list=${JSON.stringify( list )}` );
241	        // 玩家加速（快停）→ 所有乘倍一起作用（並行）；正常 → 逐個序列播放（一個乘完再乘下一個）
242	        const isSpeedUp = this.m_gameView.IsHardStop;
243	        const promises: Promise<void>[] = [];
244	        for ( const info of list )
245	        {
246	            const ctrl = this.m_gameView.EffectPlate.GetSelectFrameController( info.col, info.row );
247	            console.log( `[Multiplier] (${info.col},${info.row}) ctrl=${ctrl ? 'OK' : 'NULL'} mult=${info.multiplier}` );
248	            if ( !ctrl ) continue;
249	
250	            ctrl.SetMultiplier( true, info.multiplier );
251	
252	            const targetWorldPos = this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow( info.col, info.row );
253	            if ( isSpeedUp )
254	            {
255	                promises.push( this.PlaySingleMultiplierEffect( ctrl, info, targetWorldPos ) );
256	            }
257	            else
258	            {
259	                await this.PlaySingleMultiplierEffect( ctrl, info, targetWorldPos );
260	            }
261	        }
262	        if ( isSpeedUp ) await Promise.all( promises );
263	    }
