265	    private async PlaySingleMultiplierEffect(
266	        ctrl:           SelectFrameController,
267	        info:           MultiplierInfo,
268	        targetWorldPos: Vec3,
269	    ): Promise<void>
270	    {
271	        // 取盤面符號資料：非 Cash / Mystery 的一般符號不演出乘倍效果
272	        const symbol = this.m_gameView.SlotReels.GetSymbolInRealPlateInfo( info.col, info.row );
273	        console.log( `[Multiplier] PlaySingle (${info.col},${info.row}) realSymbol=${symbol?.Symbol} number=${symbol?.Number}` );
274	        if ( !symbol ) { console.warn( `[Multiplier] (${info.col},${info.row}) symbol=null，略過` ); return; }
275	        if ( symbol.Symbol !== Game_Define.Symbol.Cash && symbol.Symbol !== Game_Define.Symbol.Mystery )
276	        {
277	            console.warn( `[Multiplier] (${info.col},${info.row}) realSymbol=${symbol.Symbol} 非 Cash/Mystery，略過` );
278	            return;
279	        }
280	
281	        // 乘倍字飛到 Cash / Mystery 位置並打入（放大→縮回）
282	        await ctrl.PlayMultiplierFlyToTarget( targetWorldPos );
283	
284	        // Mystery 格：FG 持久乘倍 — server 已算好最終數值，只播 X_Act 動畫，不重複乘
285	        if ( symbol.Symbol === Game_Define.Symbol.Mystery )
286	        {
287	            const spineNode = this.m_gameView.EffectPlate.GetSymbolSpineNode(
288	                info.col, info.row, Game_Define.LAYERS.TWO
289	            );
290	            if ( spineNode )
291	            {
292	                const mystSpine = spineNode.getComponent( MysteryCashSpine );
293	                if ( mystSpine )
294	                {
295	                    mystSpine.SetNodeActivity( true );
296	                    mystSpine.HideNonBingoNodesForXAct();
297	                    if ( mystSpine.RewardBingoNode )
298	                    {
299	                        mystSpine.RewardBingoNode.ShowReward( false, symbol.Number );
300	                    }
301	                    const parent   = mystSpine.node.parent;
302	                    const savedIdx = parent ? mystSpine.node.getSiblingIndex() : null;
303	                    if ( parent ) mystSpine.node.setSiblingIndex( -1 );
304	                    try
305	                    {
306	                        await mystSpine.PlayAnimation( "X_Act", mystSpine.Skeleton, false, 1 );
307	                    }
308	                    finally
309	                    {
310	                        if ( savedIdx !== null && parent?.isValid && mystSpine.node.parent === parent )
311	                        {
312	                            mystSpine.node.setSiblingIndex(
313	                                Math.max( 0, Math.min( savedIdx, parent.children.length - 1 ) )
314	                            );
315	                        }
316	                    }
317	                }
318	            }
319	            this.m_gameView.EffectPlate.CleanSymbolSpineAt( info.col, info.row, Game_Define.LAYERS.TWO, true );
320	            return;
321	        }
322	
323	        const newNumber = tools.strip( ( symbol.Number ?? 0 ) * info.multiplier );
324	        symbol.Number   = newNumber;
325	
326	        // 更新盤面靜態張的 Label 並播放放大縮回 bounce
327	        const column = this.m_gameView.SlotReels.AllColumns?.[ Game_Define.MIDDLE_PLATE_INDEX ]?.[ info.col ];
328	        const cell   = column?.GetSingleCell( info.row );
329	        const labelBounce = ( (): Promise<void> =>
330	        {
331	            if ( !cell?.Label?.node ) return Promise.resolve();
332	            cell.Label.string = Common.FormatDisplayValue( newNumber );
333	            const node: Node = cell.Label.node;
334	            Tween.stopAllByTarget( node );
335	            node.setScale( 1, 1, 1 );
336	            return new Promise<void>( resolve =>
337	            {
338	                tween( node )
339	                    .to( 0.12, { scale: new Vec3( 2.2, 2.2, 1 ) }, { easing: 'backOut' } )
340	                    .to( 0.25, { scale: new Vec3( 1,   1,   1 ) }, { easing: 'backIn'  } )
341	                    .call( () => resolve() )
342	                    .start();
343	            } );
344	        } )();
345	
346	        // 若有 Cash spine 同步播放 X_Act
347	        const spineAnim = ( async () =>
348	        {
349	            const spineNode = this.m_gameView.EffectPlate.GetSymbolSpineNode( info.col, info.row, Game_Define.LAYERS.TWO );
350	            if ( !spineNode ) return;
351	            const cashSpine = spineNode.getComponent( SymbolSpine );
352	            if ( cashSpine )
353	            {
354	                cashSpine.SetNumber( newNumber );
355	                await cashSpine.PlayAnimation( "X_Act", cashSpine.Spine, false, 1 );
356	            }
357	        } )();
358	
359	        await Promise.all( [ labelBounce, spineAnim ] );
360	    }
361	
362	    // ── SHOW_SCATTER_DROP ─────────────────────────────────────────────────────
363	    private async HandleScatterDrop(): Promise<void>
364	    {
365	        const scatterPositions: CellPos[] = [];
366	        for ( let col = 0; col < Game_Define.COL; col++ )
367	        {
368	            const rowCount = Game_Define.ROW_CONFIG[ col ] ?? Game_Define.ROW;
369	            for ( let row = 0; row < rowCount; row++ )
370	            {
371	                const sym = this.m_gameView.SlotReels.GetSymbolInRealPlateInfo( col, row );
372	                if ( sym?.Symbol === Game_Define.Symbol.Scatter )
373	                {
374	                    scatterPositions.push( { col, row } );
375	                }
376	            }
377	        }
378	        await this.m_ctrl.PlayFreeGameEnter( scatterPositions, [] );
379	    }
380	}
