import { eventManager } from "db://astarte-framework/Managers";
import { tools } from "db://astarte-framework/utilis";
import { Vec3, tween, Tween, Node } from "cc";
import { ar2es2Proto } from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { Common } from "../Common/Common";
import { FEATURE_MARK_EVENT } from "./FeatureMarkEvent";
import { FeatureWheelSegmentType } from "./FeatureWheelTypes";
import {
    FeatureShowController,
    SelectFrameConfig,
    ConversionInfo,
    UpgradeInfo,
    MultiplierInfo,
    CellPos,
} from "../Feature/FeatureShowController";
import { SelectFrameController } from "../SelectFrameController";
import { SymbolSpine } from "../Spine/SymbolSpine";
import { MysteryCashSpine } from "../Spine/MysteryCashSpine";

/**
 * @ch FEATURE_MARK_EVENT 的統一接收端
 *
 * 解碼 server 封包 → 呼叫 FeatureShowController 對應演出方法。
 * 凡帶 callback 的 Dispatch，演出完成後才呼叫 callback，讓派發端可 await。
 */
export class FeatureMarkHandler
{
    private readonly m_ctrl: FeatureShowController;
    private readonly m_gameView: GameView;

    constructor( gameView: GameView )
    {
        this.m_gameView = gameView;
        this.m_ctrl     = new FeatureShowController( gameView );
    }

    public Register(): void
    {
        eventManager.Register( FEATURE_MARK_EVENT.SHOW_MARK,         this );
        eventManager.Register( FEATURE_MARK_EVENT.APPLY_TRANSFER,    this );
        eventManager.Register( FEATURE_MARK_EVENT.APPLY_UPGRADE,     this );
        eventManager.Register( FEATURE_MARK_EVENT.APPLY_MULTIPLIER,  this );
        eventManager.Register( FEATURE_MARK_EVENT.SHOW_SCATTER_DROP, this );
    }

    public Unregister(): void
    {
        eventManager.UnRegister( FEATURE_MARK_EVENT.SHOW_MARK,         this );
        eventManager.UnRegister( FEATURE_MARK_EVENT.APPLY_TRANSFER,    this );
        eventManager.UnRegister( FEATURE_MARK_EVENT.APPLY_UPGRADE,     this );
        eventManager.UnRegister( FEATURE_MARK_EVENT.APPLY_MULTIPLIER,  this );
        eventManager.UnRegister( FEATURE_MARK_EVENT.SHOW_SCATTER_DROP, this );
    }

    public OnEvent( event: string, ...args: any[] ): void
    {
        switch ( event )
        {
            // ── 轉輪落點標記：同步顯示選取框 ─────────────────────────────────
            case FEATURE_MARK_EVENT.SHOW_MARK:
            {
                const type:        FeatureWheelSegmentType = args[ 0 ];
                const positions:   number[]                = args[ 1 ] ?? [];
                const multipliers: number[]                = args[ 2 ] ?? [];
                const done: (() => void) | undefined       = args[ 3 ];
                console.log( `[FeatureMarkHandler] SHOW_MARK type=${type} positions=${JSON.stringify(positions)} multipliers=${JSON.stringify(multipliers)}` );
                const configs = this.BuildSelectFrameConfigs( type, positions, multipliers );
                this.m_ctrl.ShowSelectFrames( configs );
                done?.();
                break;
            }

            // ── 符號轉換（一般符號 → Cash，respin 前） ───────────────────────
            case FEATURE_MARK_EVENT.APPLY_TRANSFER:
            {
                const data: ar2es2Proto.ITransformInfo[] = args[ 0 ] ?? [];
                const done: (() => void) | undefined     = args[ 1 ];
                console.log( `[FeatureMarkHandler] APPLY_TRANSFER count=${data.length}`, data );
                const conversionList = this.BuildConversionList( data );
                this.m_ctrl.PlayConversion( conversionList )
                    .then( () => done?.() )
                    .catch( e => console.error( "[FeatureMarkHandler] APPLY_TRANSFER 演出失敗:", e ) );
                break;
            }

            // ── 升級（Cash → Mystery，respin 後） ────────────────────────────
            case FEATURE_MARK_EVENT.APPLY_UPGRADE:
            {
                const data: ar2es2Proto.ITransformInfo[] = args[ 0 ] ?? [];
                const done: (() => void) | undefined     = args[ 1 ];
                console.log( `[FeatureMarkHandler] APPLY_UPGRADE count=${data.length}`, data );
                const upgradeList = this.BuildUpgradeList( data );
                this.m_ctrl.PlayUpgrade( upgradeList )
                    .then( () => done?.() )
                    .catch( e => console.error( "[FeatureMarkHandler] APPLY_UPGRADE 演出失敗:", e ) );
                break;
            }

            // ── 乘倍（結算前乘上倍率） ────────────────────────────────────────
            case FEATURE_MARK_EVENT.APPLY_MULTIPLIER:
            {
                const features: ar2es2Proto.IFeatureResult[] = args[ 0 ] ?? [];
                const done: (() => void) | undefined          = args[ 1 ];
                console.log( `[FeatureMarkHandler] APPLY_MULTIPLIER count=${features.length}`, features );
                const multiplierList = this.BuildMultiplierList( features );
                this.PlayMultiplierWithStamp( multiplierList )
                    .then( () => done?.() )
                    .catch( e => console.error( "[FeatureMarkHandler] APPLY_MULTIPLIER 演出失敗:", e ) );
                break;
            }

            // ── Scatter 補齊 + FG 進場 ────────────────────────────────────────
            case FEATURE_MARK_EVENT.SHOW_SCATTER_DROP:
            {
                const done: (() => void) | undefined = args[ 0 ];
                console.log( `[FeatureMarkHandler] SHOW_SCATTER_DROP` );
                this.HandleScatterDrop()
                    .then( () => done?.() )
                    .catch( e => console.error( "[FeatureMarkHandler] SHOW_SCATTER_DROP 演出失敗:", e ) );
                break;
            }
        }
    }

    // ── SHOW_MARK ─────────────────────────────────────────────────────────────
    private BuildSelectFrameConfigs(
        type:        FeatureWheelSegmentType,
        positions:   number[],
        multipliers: number[],
    ): SelectFrameConfig[]
    {
        // FreeGame / GrandJP 由 JP_EVENT / EnterFreeState 另行處理，不顯示選取框
        if ( type === FeatureWheelSegmentType.FreeGame ||
             type === FeatureWheelSegmentType.GrandJP )
        {
            return [];
        }

        return positions
            .map( ( pos, i ) =>
            {
                const decoded = Common.DecodeServerPosByRowConfig( pos );
                if ( !decoded ) return null;

                const cfg: SelectFrameConfig = { col: decoded.col, row: decoded.row };

                switch ( type )
                {
                    case FeatureWheelSegmentType.Multiplier:
                    {
                        // 每個位置有獨立倍率；退回 index 0 作為保底
                        const m = multipliers?.[ i ] ?? multipliers?.[ 0 ];
                        if ( m != null ) cfg.multiplier = m;
                        break;
                    }
                    case FeatureWheelSegmentType.Upgrade:
                        cfg.upgrade = true;
                        break;
                    case FeatureWheelSegmentType.SymbolConvert:
                        cfg.conversion = true;
                        break;
                }

                return cfg;
            } )
            .filter( ( cfg ): cfg is SelectFrameConfig => cfg !== null );
    }

    // ── APPLY_TRANSFER ────────────────────────────────────────────────────────
    private BuildConversionList( data: ar2es2Proto.ITransformInfo[] ): ConversionInfo[]
    {
        const list: ConversionInfo[] = [];
        for ( const item of data )
        {
            const decoded = Common.DecodeServerPosByRowConfig( item.Pos ?? 0 );
            if ( !decoded ) continue;
            list.push( {
                col:    decoded.col,
                row:    decoded.row,
                symbol: item.Symbol ?? Game_Define.Symbol.Cash,
                number: item.Number ?? 0,
            } );
        }
        return list;
    }

    // ── APPLY_UPGRADE ─────────────────────────────────────────────────────────
    private BuildUpgradeList( data: ar2es2Proto.ITransformInfo[] ): UpgradeInfo[]
    {
        const list: UpgradeInfo[] = [];
        for ( const item of data )
        {
            const decoded = Common.DecodeServerPosByRowConfig( item.Pos ?? 0 );
            if ( !decoded ) continue;
            list.push( {
                col:     decoded.col,
                row:     decoded.row,
                symbol:  item.Symbol   ?? Game_Define.Symbol.Mystery,
                number:  item.Number   ?? 0,
                jpState: item.JPState  ?? 0,
            } );
        }
        return list;
    }

    // ── APPLY_MULTIPLIER ──────────────────────────────────────────────────────
    private BuildMultiplierList( features: ar2es2Proto.IFeatureResult[] ): MultiplierInfo[]
    {
        // 同一位置可能在 Positions 中出現多次（server 送多段倍率），以 compound 方式合算避免並行 race。
        const compoundMap = new Map<string, MultiplierInfo>();
        for ( const wf of features )
        {
            const positions = wf.Positions ?? [];
            for ( let i = 0; i < positions.length; i++ )
            {
                const decoded = Common.DecodeServerPosByRowConfig( positions[ i ] );
                if ( !decoded ) continue;
                // 每個位置有獨立倍率；退回 index 0 作為保底
                const multiplier = wf.Multipliers?.[ i ] ?? wf.Multipliers?.[ 0 ] ?? 1;
                const key = `${ decoded.col },${ decoded.row }`;
                const existing = compoundMap.get( key );
                if ( existing )
                {
                    existing.multiplier *= multiplier;
                }
                else
                {
                    compoundMap.set( key, { col: decoded.col, row: decoded.row, multiplier } );
                }
            }
        }
        return Array.from( compoundMap.values() );
    }

    // ── APPLY_MULTIPLIER ──────────────────────────────────────────────────────
    private async PlayMultiplierWithStamp( list: MultiplierInfo[] ): Promise<void>
    {
        console.log( `[Multiplier] PlayMultiplierWithStamp list=${JSON.stringify( list )}` );
        // 玩家加速（快停）→ 所有乘倍一起作用（並行）；正常 → 逐個序列播放（一個乘完再乘下一個）
        const isSpeedUp = this.m_gameView.IsHardStop;
        const promises: Promise<void>[] = [];
        for ( const info of list )
        {
            const ctrl = this.m_gameView.EffectPlate.GetSelectFrameController( info.col, info.row );
            console.log( `[Multiplier] (${info.col},${info.row}) ctrl=${ctrl ? 'OK' : 'NULL'} mult=${info.multiplier}` );
            if ( !ctrl ) continue;

            ctrl.SetMultiplier( true, info.multiplier );

            const targetWorldPos = this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromColRow( info.col, info.row );
            if ( isSpeedUp )
            {
                promises.push( this.PlaySingleMultiplierEffect( ctrl, info, targetWorldPos ) );
            }
            else
            {
                await this.PlaySingleMultiplierEffect( ctrl, info, targetWorldPos );
            }
        }
        if ( isSpeedUp ) await Promise.all( promises );
    }

    private async PlaySingleMultiplierEffect(
        ctrl:           SelectFrameController,
        info:           MultiplierInfo,
        targetWorldPos: Vec3,
    ): Promise<void>
    {
        // 取盤面符號資料：非 Cash / Mystery 的一般符號不演出乘倍效果
        const symbol = this.m_gameView.SlotReels.GetSymbolInRealPlateInfo( info.col, info.row );
        console.log( `[Multiplier] PlaySingle (${info.col},${info.row}) realSymbol=${symbol?.Symbol} number=${symbol?.Number}` );
        if ( !symbol ) { console.warn( `[Multiplier] (${info.col},${info.row}) symbol=null，略過` ); return; }
        if ( symbol.Symbol !== Game_Define.Symbol.Cash && symbol.Symbol !== Game_Define.Symbol.Mystery )
        {
            console.warn( `[Multiplier] (${info.col},${info.row}) realSymbol=${symbol.Symbol} 非 Cash/Mystery，略過` );
            return;
        }

        // 乘倍字飛到 Cash / Mystery 位置並打入（放大→縮回）
        await ctrl.PlayMultiplierFlyToTarget( targetWorldPos );

        // Mystery 格：FG 持久乘倍 — server 已算好最終數值，只播 X_Act 動畫，不重複乘
        if ( symbol.Symbol === Game_Define.Symbol.Mystery )
        {
            const spineNode = this.m_gameView.EffectPlate.GetSymbolSpineNode(
                info.col, info.row, Game_Define.LAYERS.TWO
            );
            if ( spineNode )
            {
                const mystSpine = spineNode.getComponent( MysteryCashSpine );
                if ( mystSpine )
                {
                    mystSpine.SetNodeActivity( true );
                    mystSpine.HideNonBingoNodesForXAct();
                    if ( mystSpine.RewardBingoNode )
                    {
                        mystSpine.RewardBingoNode.ShowReward( false, symbol.Number );
                    }
                    const parent   = mystSpine.node.parent;
                    const savedIdx = parent ? mystSpine.node.getSiblingIndex() : null;
                    if ( parent ) mystSpine.node.setSiblingIndex( -1 );
                    try
                    {
                        await mystSpine.PlayAnimation( "X_Act", mystSpine.Skeleton, false, 1 );
                    }
                    finally
                    {
                        if ( savedIdx !== null && parent?.isValid && mystSpine.node.parent === parent )
                        {
                            mystSpine.node.setSiblingIndex(
                                Math.max( 0, Math.min( savedIdx, parent.children.length - 1 ) )
                            );
                        }
                    }
                }
            }
            this.m_gameView.EffectPlate.CleanSymbolSpineAt( info.col, info.row, Game_Define.LAYERS.TWO, true );
            return;
        }

        const newNumber = tools.strip( ( symbol.Number ?? 0 ) * info.multiplier );
        symbol.Number   = newNumber;

        // 更新盤面靜態張的 Label 並播放放大縮回 bounce
        const column = this.m_gameView.SlotReels.AllColumns?.[ Game_Define.MIDDLE_PLATE_INDEX ]?.[ info.col ];
        const cell   = column?.GetSingleCell( info.row );
        const labelBounce = ( (): Promise<void> =>
        {
            if ( !cell?.Label?.node ) return Promise.resolve();
            cell.Label.string = Common.FormatDisplayValue( newNumber );
            const node: Node = cell.Label.node;
            Tween.stopAllByTarget( node );
            node.setScale( 1, 1, 1 );
            return new Promise<void>( resolve =>
            {
                tween( node )
                    .to( 0.12, { scale: new Vec3( 2.2, 2.2, 1 ) }, { easing: 'backOut' } )
                    .to( 0.25, { scale: new Vec3( 1,   1,   1 ) }, { easing: 'backIn'  } )
                    .call( () => resolve() )
                    .start();
            } );
        } )();

        // 若有 Cash spine 同步播放 X_Act
        const spineAnim = ( async () =>
        {
            const spineNode = this.m_gameView.EffectPlate.GetSymbolSpineNode( info.col, info.row, Game_Define.LAYERS.TWO );
            if ( !spineNode ) return;
            const cashSpine = spineNode.getComponent( SymbolSpine );
            if ( cashSpine )
            {
                cashSpine.SetNumber( newNumber );
                await cashSpine.PlayAnimation( "X_Act", cashSpine.Spine, false, 1 );
            }
        } )();

        await Promise.all( [ labelBounce, spineAnim ] );
    }

    // ── SHOW_SCATTER_DROP ─────────────────────────────────────────────────────
    private async HandleScatterDrop(): Promise<void>
    {
        const scatterPositions: CellPos[] = [];
        for ( let col = 0; col < Game_Define.COL; col++ )
        {
            const rowCount = Game_Define.ROW_CONFIG[ col ] ?? Game_Define.ROW;
            for ( let row = 0; row < rowCount; row++ )
            {
                const sym = this.m_gameView.SlotReels.GetSymbolInRealPlateInfo( col, row );
                if ( sym?.Symbol === Game_Define.Symbol.Scatter )
                {
                    scatterPositions.push( { col, row } );
                }
            }
        }
        await this.m_ctrl.PlayFreeGameEnter( scatterPositions, [] );
    }
}

